+    #[test]
+    fn parse_version_with_prerelease() {
+        let v = ApiVersion::parse("1.2.3-alpha.1").unwrap();
+        assert_eq!(
+            v,
+            ApiVersion {
+                major: 1,
+                minor: 2,
+                patch: 3
+            }
+        );
+        let v = ApiVersion::parse("1.2.3+build.42").unwrap();
+        assert_eq!(
+            v,
+            ApiVersion {
+                major: 1,
+                minor: 2,
+                patch: 3
+            }
+        );
+        let v = ApiVersion::parse("1.2.3-beta.1+build.42").unwrap();
+        assert_eq!(
+            v,
+            ApiVersion {
+                major: 1,
+                minor: 2,
+                patch: 3
             }
         );
     }
